def convertDocument(input_file, output_file, output_format):
    """
    Convert documents between formats using LibreOffice headless mode.
    
    Supported conversions include:
    - Document formats: docx, doc, odt, rtf, txt, html
    - Spreadsheet formats: xlsx, xls, ods, csv
    - Presentation formats: pptx, ppt, odp
    - PDF output from any of the above
    - Image formats: png, jpg, bmp, gif, tiff (for single-page documents)
    
    Args:
        input_file (str): Path to the input file.
        output_file (str): Path to the desired output file.
        output_format (str): Target format (e.g., 'pdf', 'docx', 'html', 'txt', 'png', 'jpg', 'csv', etc.)
    
    Returns:
        bool: True if conversion was successful, False otherwise.
    
    Raises:
        FileNotFoundError: If the input file doesn't exist.
        RuntimeError: If LibreOffice is not found or conversion fails.
    
    Example:
        convertDocument('input.docx', 'output.pdf', 'pdf')
        convertDocument('report.pdf', 'report.docx', 'docx')
        convertDocument('data.xlsx', 'data.csv', 'csv')
    """
    
    # Validate input file exists
    input_path = Path(input_file).resolve()
    if not input_path.exists():
        raise FileNotFoundError(f"Input file not found: {input_file}")
    
    if not input_path.is_file():
        raise ValueError(f"Input path is not a file: {input_file}")
    
    # Find LibreOffice executable
    libreoffice_path = _find_libreoffice()
    if libreoffice_path is None:
        raise RuntimeError(
            "LibreOffice not found. Please install LibreOffice and ensure it's in your PATH. "
            "Download from: https://www.libreoffice.org/download/"
        )
    
    # Resolve output path
    output_path = Path(output_file).resolve()
    output_dir = output_path.parent
    
    # Create output directory if it doesn't exist
    output_dir.mkdir(parents=True, exist_ok=True)
    
    # Normalize format
    output_format = output_format.lower().strip().lstrip('.')
    
    # Map common format aliases
    format_aliases = {
        'jpeg': 'jpg',
        'tif': 'tiff',
        'htm': 'html',
        'text': 'txt',
    }
    output_format = format_aliases.get(output_format, output_format)
    
    # Determine the LibreOffice filter to use
    lo_filter = _get_libreoffice_filter(output_format, input_path.suffix.lower())
    
    # Use a temporary directory for LibreOffice output since it doesn't let
    # you specify the exact output filename directly
    with tempfile.TemporaryDirectory() as temp_dir:
        # Build the LibreOffice command
        cmd = [
            libreoffice_path,
            '--headless',
            '--norestore',
            '--nofirststartwizard',
            '--nologo',
            '--convert-to',
        ]
        
        if lo_filter:
            cmd.append(f'{output_format}:{lo_filter}')
        else:
            cmd.append(output_format)
        
        cmd.extend([
            '--outdir', temp_dir,
            str(input_path)
        ])
        
        # Set environment to avoid profile locking issues
        env = os.environ.copy()
        user_profile_dir = tempfile.mkdtemp(prefix='lo_profile_')
        env['UserInstallation'] = f'file://{user_profile_dir}'
        
        try:
            # Execute LibreOffice conversion
            result = subprocess.run(
                cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                timeout=300,  # 5-minute timeout
                env=env,
                cwd=temp_dir
            )
            
            if result.returncode != 0:
                stderr_output = result.stderr.decode('utf-8', errors='replace').strip()
                stdout_output = result.stdout.decode('utf-8', errors='replace').strip()
                error_msg = stderr_output or stdout_output or "Unknown error"
                raise RuntimeError(
                    f"LibreOffice conversion failed (exit code {result.returncode}): {error_msg}\n"
                    f"Command: {' '.join(cmd)}"
                )
            
            # Find the converted file in the temp directory
            converted_file = _find_converted_file(temp_dir, input_path.stem, output_format)
            
            if converted_file is None:
                # List what's actually in the temp dir for debugging
                temp_contents = list(Path(temp_dir).iterdir())
                raise RuntimeError(
                    f"Conversion appeared to succeed but output file not found in temp directory. "
                    f"Expected format: {output_format}, Input stem: {input_path.stem}. "
                    f"Temp dir contents: {[f.name for f in temp_contents]}"
                )
            
            # Move the converted file to the desired output path
            shutil.move(str(converted_file), str(output_path))
            
            if output_path.exists():
                print(f"Successfully converted '{input_file}' -> '{output_file}' (format: {output_format})")
                return True
            else:
                raise RuntimeError("File move operation failed; output file does not exist.")
                
        except subprocess.TimeoutExpired:
            raise RuntimeError(
                f"LibreOffice conversion timed out after 300 seconds for file: {input_file}"
            )
        finally:
            # Clean up the temporary user profile
            try:
                shutil.rmtree(user_profile_dir, ignore_errors=True)
            except Exception:
                pass


def _find_libreoffice():
    """
    Find the LibreOffice executable on the system.
    
    Returns:
        str or None: Path to LibreOffice executable, or None if not found.
    """
    # Common executable names
    executable_names = [
        'libreoffice',
        'soffice',
        'libreoffice7.0',
        'libreoffice7.1',
        'libreoffice7.2',
        'libreoffice7.3',
        'libreoffice7.4',
        'libreoffice7.5',
        'libreoffice7.6',
        'libreoffice24.2',
        'libreoffice24.8',
    ]
    
    # Check PATH first
    for name in executable_names:
        path = shutil.which(name)
        if path:
            return path
    
    # Common installation paths by OS
    import platform
    system = platform.system()
    
    common_paths = []
    
    if system == 'Windows':
        program_files = [
            os.environ.get('ProgramFiles', r'C:\Program Files'),
            os.environ.get('ProgramFiles(x86)', r'C:\Program Files (x86)'),
        ]
        for pf in program_files:
            if pf:
                common_paths.extend([
                    os.path.join(pf, 'LibreOffice', 'program', 'soffice.exe'),
                    os.path.join(pf, 'LibreOffice', 'program', 'soffice.com'),
                ])
                # Check versioned directories
                lo_dir = os.path.join(pf, 'LibreOffice')
                if os.path.isdir(lo_dir):
                    for entry in os.listdir(lo_dir):
                        common_paths.append(
                            os.path.join(lo_dir, entry, 'program', 'soffice.exe')
                        )
                        
    elif system == 'Darwin':  # macOS
        common_paths.extend([
            '/Applications/LibreOffice.app/Contents/MacOS/soffice',
            os.path.expanduser('~/Applications/LibreOffice.app/Contents/MacOS/soffice'),
        ])
        
    else:  # Linux and other Unix-like
        common_paths.extend([
            '/usr/bin/libreoffice',
            '/usr/bin/soffice',
            '/usr/local/bin/libreoffice',
            '/usr/local/bin/soffice',
            '/snap/bin/libreoffice',
            '/usr/lib/libreoffice/program/soffice',
            '/opt/libreoffice/program/soffice',
        ])
        # Check /opt for versioned installations
        opt_path = '/opt'
        if os.path.isdir(opt_path):
            try:
                for entry in os.listdir(opt_path):
                    if entry.startswith('libreoffice'):
                        common_paths.append(
                            os.path.join(opt_path, entry, 'program', 'soffice')
                        )
            except PermissionError:
                pass
    
    for path in common_paths:
        if os.path.isfile(path) and os.access(path, os.X_OK):
            return path
    
    return None


def _get_libreoffice_filter(output_format, input_extension):
    """
    Get the appropriate LibreOffice export filter for the given format combination.
    
    Args:
        output_format (str): Target format (lowercase).
        input_extension (str): Input file extension (lowercase, with dot).
    
    Returns:
        str or None: Filter name, or None to use default.
    """
    # Map of output format to specific filters
    filter_map = {
        # Image formats
        'png': 'draw_png_Export' if input_extension in ['.odg', '.svg'] else 'writer_png_Export',
        'jpg': 'draw_jpg_Export' if input_extension in ['.odg', '.svg'] else 'writer_jpg_Export',
        'jpeg': 'draw_jpg_Export' if input_extension in ['.odg', '.svg'] else 'writer_jpg_Export',
        'bmp': 'draw_bmp_Export' if input_extension in ['.odg', '.svg'] else 'writer_bmp_Export',
        'gif': 'draw_gif_Export' if input_extension in ['.odg', '.svg'] else 'writer_gif_Export',
        'tiff': 'draw_tiff_Export' if input_extension in ['.odg', '.svg'] else 'writer_tiff_Export',
        'svg': 'draw_svg_Export',
        'eps': 'draw_eps_Export',
        
        # PDF with specific settings
        'pdf': None,  # LibreOffice handles PDF well with defaults
        
        # Document formats - usually don't need explicit filters
        'docx': 'MS Word 2007 XML',
        'doc': 'MS Word 97',
        'rtf': 'Rich Text Format',
        'odt': 'writer8',
        'txt': 'Text',
        'html': 'HTML (StarWriter)',
        'xhtml': 'XHTML Writer File',
        
        # Spreadsheet formats
        'xlsx': 'Calc MS Excel 2007 XML',
        'xls': 'MS Excel 97',
        'ods': 'calc8',
        'csv': 'Text - txt - csv (StarCalc)',
        
        # Presentation formats
        'pptx': 'Impress MS PowerPoint 2007 XML',
        'ppt': 'MS PowerPoint 97',
        'odp': 'impress8',
    }
    
    return filter_map.get(output_format)


def _find_converted_file(directory, input_stem, output_format):
    """
    Find the converted file in the output directory.
    
    LibreOffice names the output file using the input filename stem
    with the new extension.
    
    Args:
        directory (str): Directory to search.
        input_stem (str): Original filename without extension.
        output_format (str): Expected output format/extension.
    
    Returns:
        Path or None: Path to the converted file, or None if not found.
    """
    dir_path = Path(directory)
    
    # Try exact match first
    expected_name = f"{input_stem}.{output_format}"
    expected_path = dir_path / expected_name
    if expected_path.exists():
        return expected_path
    
    # Try case-insensitive match
    for file_path in dir_path.iterdir():
        if file_path.is_file():
            if file_path.stem.lower() == input_stem.lower():
                if file_path.suffix.lower() == f'.{output_format}':
                    return file_path
    
    # If still not found, try to find any file with the right extension
    for file_path in dir_path.iterdir():
        if file_path.is_file() and file_path.suffix.lower() == f'.{output_format}':
            return file_path
    
    # Last resort: return any file that was created (excluding hidden files)
    for file_path in dir_path.iterdir():
        if file_path.is_file() and not file_path.name.startswith('.'):
            return file_path
    
    return None


def batch_convert(input_files, output_dir, output_format):
    """
    Convert multiple files to the specified format.
    
    Args:
        input_files (list): List of input file paths.
        output_dir (str): Directory for output files.
        output_format (str): Target format.
    
    Returns:
        dict: Mapping of input files to (success: bool, output_path_or_error: str).
    """
    results = {}
    output_dir_path = Path(output_dir)
    output_dir_path.mkdir(parents=True, exist_ok=True)
    
    for input_file in input_files:
        input_path = Path(input_file)
        output_file = output_dir_path / f"{input_path.stem}.{output_format}"
        
        try:
            success = convertDocument(str(input_path), str(output_file), output_format)
            results[input_file] = (success, str(output_file))
        except Exception as e:
            results[input_file] = (False, str(e))
            print(f"Failed to convert '{input_file}': {e}")
    
    return results


